//————————三角形问题————————
#include <stdio.h>

int main()
{
    char san(int x,int y,int z);
    void maxtomin(int a[]);

    int a,b,c,d;
    scanf("%d %d %d %d",&a,&b,&c,&d);
    int s[4]={a,b,c,d};
    maxtomin(s);
    a=s[0];b=s[1];c=s[2];d=s[3];
    if(san(a,b,c)=='y'||san(b,c,d)=='y') printf("TRIANGLE");
    else if(san(a,b,c)=='d'||san(b,c,d)=='d') printf("SEGMENT");
    else if(san(a,b,c)=='n'&&san(b,c,d)=='n') printf("IMPOSSIBLE");

    return 0;
}

void maxtomin(int a[])
{
    int i,j,t;
    for(i=0; i<4; i++)
    {
        for(j=i+1; j<4; j++)
        {
            if(a[i]<a[j])
            {
                t = a[i];
                a[i] = a[j];
                a[j] = t;
            }
            else continue;
        }
    }
}

char san(int x,int y,int z)
{
    char r;
    if(x+y>z&&x+z>y&&z+y>x) r='y';
    else if(x+y==z||x+z==y||y+z==x) r='d';
    else r='n';

    return r;
}

