use std::io;

fn solve(nums: &Vec<u8>) -> &str {
    let mut res = false;
    if nums[0] + nums[1] > nums[2] {
        return "TRIANGLE";
    } else if nums[0] + nums[1] == nums[2] {
        res = true;
    }
    if nums[1] + nums[2] > nums[3] {
        "TRIANGLE"
    } else if nums[1] + nums[2] == nums[3] || res {
        "SEGMENT"
    } else {
        "IMPOSSIBLE"
    }
}

fn main() {
    let mut input = String::with_capacity(7);
    io::stdin().read_line(&mut input).unwrap();
    let mut nums: Vec<u8> = input
        .trim()
        .split_whitespace()
        .map(|a| a.parse().unwrap())
        .collect();

    nums.sort_unstable();
    print!("{}", solve(&nums));
}
